detailed_optimizations.code_changes:
将k循环移到最外层，对i和j循环进行分块。

#pragma scop
for (k = 0; k < _PB_M; k++) {
  for (ii = 0; ii < _PB_N; ii += TILE_SIZE) {
    for (i = ii; i < min(ii + TILE_SIZE, _PB_N); i++) {
      for (j = 0; j <= i; j++) {
        C[i][j] += alpha * A[i][k] * A[j][k];
      }
    }
  }
}
// 单独的beta乘法循环
for (i = 0; i < _PB_N; i++) {
  for (j = 0; j <= i; j++) {
    C[i][j] *= beta;
  }
}
#pragma endscop

使用编译器指令强制向量化，并展开内层循环。

#pragma omp simd
for (j = 0; j <= i - 3; j += 4) {
  C[i][j] += alpha * A[i][k] * A[j][k];
  C[i][j+1] += alpha * A[i][k] * A[j+1][k];
  C[i][j+2] += alpha * A[i][k] * A[j+2][k];
  C[i][j+3] += alpha * A[i][k] * A[j+3][k];
}
// 处理剩余元素

1) 将A矩阵转置为A^T，使A[j][k]访问连续内存；
2) 使用__builtin_prefetch预取数据。

// 转置A矩阵
DATA_TYPE POLYBENCH_2D(AT, M, N, m, n);
for (i = 0; i < n; i++)
  for (k = 0; k < m; k++)
    AT[k][i] = A[i][k];

// 修改内核：
for (k = 0; k < _PB_M; k++) {
  for (i = 0; i < _PB_N; i++) {
    DATA_TYPE aik = alpha * AT[k][i];  // 现在AT[k][i]是连续访问
    for (j = 0; j <= i; j++) {
      C[i][j] += aik * AT[k][j];
    }
  }
}
